DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$b = non_zero_random(-4,4);
Context("Fraction");
$m = Fraction(1/random(2,9));
$x1 = 0;
$y1 = $b;
$x2 = 1/$m;
$y2 = $b+1;
$rise = $y2-$y1;
$run = $x2-$x1;
Context()->variables->add(y=>'Real');
Context()->noreduce('(-x)-y','(-x)+y');
parser::Assignment->Allow;
$ansSI = Formula("y = $m*x+$b")->reduce;
$xmax = max(5, 1/$m + 1);
$xmin = -$xmax;
$ymin = -7;
$ymax = 7;
($start,$stop) = (num_sort($xmin,$xmax,($ymin-$b)/$m,($ymax-$b)/$m))[1,2];

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[
      xmin = $xmin,
      xmax = $xmax,
      ymin = $ymin,
      ymax = $ymax,
      xtick =,
      ytick =,
      minor xtick = {$xmin,...,$xmax},
      minor ytick = {$ymin,...,$ymax},
      grid = minor,
      width=0.33\orccaprintwidth
    ]
    \addplot+[domain=$start:$stop] {$m*x+$b};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
In the given graph, what is the line's slope-intercept equation?

>> [@image(insertGraph($image_1), width=>600)@]*  <<

[_]{$ansSI}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
